// =====================================================
// Resolver palabras clave del mes a partir de fecha_nomina
// Genera variantes para buscar archivos por nombre
// =====================================================

const fecha = $json.fecha_nomina || '';

const MONTHS = {
  1: { name: 'enero',      abbr: 'ene', num: '01' },
  2: { name: 'febrero',    abbr: 'feb', num: '02' },
  3: { name: 'marzo',      abbr: 'mar', num: '03' },
  4: { name: 'abril',      abbr: 'abr', num: '04' },
  5: { name: 'mayo',       abbr: 'may', num: '05' },
  6: { name: 'junio',      abbr: 'jun', num: '06' },
  7: { name: 'julio',      abbr: 'jul', num: '07' },
  8: { name: 'agosto',     abbr: 'ago', num: '08' },
  9: { name: 'septiembre', abbr: 'sep', num: '09' },
  10: { name: 'octubre',   abbr: 'oct', num: '10' },
  11: { name: 'noviembre', abbr: 'nov', num: '11' },
  12: { name: 'diciembre',  abbr: 'dic', num: '12' },
};

// Parsear año y mes
let y, mo;
const m1 = fecha.match(/^(\d{4})-(\d{1,2})/);
if (m1) { y = +m1[1]; mo = +m1[2]; }
else {
  const m2 = fecha.match(/^(\d{4})(\d{2})$/);
  if (m2) { y = +m2[1]; mo = +m2[2]; }
  else throw new Error(`No se pudo parsear fecha_nomina: '${fecha}'. Usa formato YYYY-MM.`);
}

const info = MONTHS[mo];
if (!info) throw new Error(`Mes inválido: ${mo}`);

// Variantes de búsqueda: junio, jun, 06, 2025-06, 202506
const keywords = [
  info.name,                    // junio
  info.abbr,                    // jun
  info.num,                     // 06
  `${y}-${info.num}`,           // 2025-06
  `${y}${info.num}`,            // 202506
  `${info.name}_${y}`,          // junio_2025
  `${info.name} ${y}`,          // junio 2025
  `${info.abbr}_${y}`,          // jun_2025
  `${info.abbr}${y}`,           // jun2025
];

return [{
  json: {
    ...$json,
    y,
    mo,
    month_name: info.name,
    month_abbr: info.abbr,
    month_num: info.num,
    keywords,
  }
}];

// =====================================================
// Filtrar archivos del mes actual por keywords
// Recibe: items de Google Drive (listado de archivos)
// Usa: keywords del nodo 'Resolver mes y keywords'
// =====================================================

const config = $('Resolver mes y keywords').first().json;
const keywords = config.keywords || [];

const normalize = s => (s || '').toString()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/[^a-z0-9]/g, '');

const normalizedKW = keywords.map(normalize);

const matches = [];
for (const item of items) {
  const name = normalize(item.json.name || '');
  const found = normalizedKW.some(kw => name.includes(kw));
  if (found) matches.push(item);
}

if (matches.length === 0) {
  console.warn(`No se encontraron archivos que coincidan con: ${keywords.join(', ')}`);
  console.warn(`Archivos disponibles: ${items.map(i => i.json.name).join(', ')}`);
}

return matches.length > 0 ? matches : [{ json: { _empty: true, _source: 'filtro', keywords } }];

// Filtrar descuentos del mes
const config = $('Resolver mes y keywords').first().json;
const keywords = config.keywords || [];

const normalize = s => (s || '').toString()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/[^a-z0-9]/g, '');

const normalizedKW = keywords.map(normalize);

const matches = [];
for (const item of items) {
  const name = normalize(item.json.name || '');
  const found = normalizedKW.some(kw => name.includes(kw));
  if (found) matches.push(item);
}

return matches.length > 0 ? matches : [{ json: { _empty: true, _source: 'descuentos' } }];

// Filtrar PDFs del mes (quirografarios + fondos de reserva)
const config = $('Resolver mes y keywords').first().json;
const keywords = config.keywords || [];

const normalize = s => (s || '').toString()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/[^a-z0-9]/g, '');

const normalizedKW = keywords.map(normalize);

const matches = [];
for (const item of items) {
  const name = normalize(item.json.name || '');
  const found = normalizedKW.some(kw => name.includes(kw));
  if (found) matches.push(item);
}

return matches.length > 0 ? matches : [{ json: { _empty: true, _source: 'pdfs' } }];

// Filtrar ajustes del mes
const config = $('Resolver mes y keywords').first().json;
const keywords = config.keywords || [];

const normalize = s => (s || '').toString()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/[^a-z0-9]/g, '');

const normalizedKW = keywords.map(normalize);

const matches = [];
for (const item of items) {
  const name = normalize(item.json.name || '');
  const found = normalizedKW.some(kw => name.includes(kw));
  if (found) matches.push(item);
}

// Ajustes es siempre opcional
return matches.length > 0 ? matches : [{ json: { _empty: true, _source: 'ajustes' } }];

// Clasificar PDFs: quirografarios (file2) vs fondos de reserva (file3) vs hipotecarios (file5)

const normalize = s => (s || '').toString()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .toLowerCase();

const results = { quirografarios: null, fondos: null, hipotecarios: null };

for (const item of items) {
  if (item.json._empty) continue;
  const name = normalize(item.json.name);

  if (name.includes('hipotec')) {
    results.hipotecarios = item.json.id;
  } else if (name.includes('quirog') || name.includes('quiro') || name.includes('prestamo')) {
    results.quirografarios = item.json.id;
  } else if (name.includes('fondo') || name.includes('reserva') || name.includes('fr')) {
    results.fondos = item.json.id;
  } else {
    if (!results.quirografarios) results.quirografarios = item.json.id;
    else if (!results.fondos) results.fondos = item.json.id;
  }
}

return [{ json: results }];

// Node: Armar lote (Run Once for All Items)

// Helpers
function toNum(v) {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;

  let s = String(v).trim().replace(/[^\d.,-]/g, '');
  if (!s) return 0;

  const comma = s.lastIndexOf(',');
  const dot = s.lastIndexOf('.');

  if (comma > dot) {
    // "1.234,56" -> "1234.56"
    s = s.slice(0, comma).replace(/[^\d-]/g, '') + '.' + s.slice(comma + 1).replace(/\D/g, '');
  } else if (dot > comma) {
    // "1,234.56" -> "1234.56"
    s = s.slice(0, dot).replace(/[^\d-]/g, '') + '.' + s.slice(dot + 1).replace(/\D/g, '');
  }

  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

function normCedula(x) {
  if (x === null || x === undefined) return '';
  let s = String(x).trim().replace(/\D/g, '');
  // Si viene como número, puede perder ceros; rellenamos solo si son dígitos y < 10
  if (/^\d+$/.test(s) && s.length > 0 && s.length < 10) s = s.padStart(10, '0');
  return s;
}

function frModo(fr_derecho, fr_acumulacion) {
  if (!fr_derecho) return 'sin_derecho';
  return fr_acumulacion ? 'acumula' : 'paga';
}

function emptyToNull(x) {
  if (x === '' || x === undefined) return null;
  return x;
}

function pickIdx(obj, fallback) {
  // intenta varias llaves comunes; si no hay, usa fallback
  const candidates = [
    obj?.idx,
    obj?._idx,
    obj?.__idx,
    obj?.rowIndex,
    obj?.row_index,
    obj?.source_idx,
  ];

  for (const c of candidates) {
    if (c === 0) return 0;
    if (c !== null && c !== undefined && c !== '') {
      const n = Number(c);
      if (Number.isFinite(n)) return n;
    }
  }
  return fallback;
}

function truthy(v) {
  // true / "true" / 1 / "1" / "yes" / "si" / "x"
  if (v === true) return true;
  if (v === false || v === null || v === undefined) return false;
  const s = String(v).trim().toLowerCase();
  return ['true', '1', 'yes', 'si', 'sí', 'x'].includes(s);
}

const monthNames = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const monthAbbr  = ['ene','feb','mar','abr','may','jun','jul','ago','sep','oct','nov','dic'];

// ----------------------------------------------------
// IMPORTANTE: NO hacer swap de fr_derecho / fr_tiene_cargos
// ----------------------------------------------------
const SWAP_DER_CARGOS = false;

// 1) Input base: viene 1 item con { empresa, empleados:[...] }
const inJson = items[0]?.json ?? {};
const empresa = inJson.empresa ?? null;
const empleadosIn = Array.isArray(inJson.empleados) ? inJson.empleados : [];

// 2) Traer periodo (si existe el nodo); fallback al propio item si ya lo trae
const periodoFromNode = ($items('Periodo nomina')?.[0]?.json) ?? {};
const fecha_nomina   = periodoFromNode.fecha_nomina   ?? inJson.fecha_nomina   ?? null;
const periodo_key    = periodoFromNode.periodo_key    ?? inJson.periodo_key    ?? null;
const periodo_inicio = periodoFromNode.periodo_inicio ?? inJson.periodo_inicio ?? null;
const periodo_fin    = periodoFromNode.periodo_fin    ?? inJson.periodo_fin    ?? null;
const y              = periodoFromNode.y              ?? inJson.y              ?? null;
const mo             = periodoFromNode.mo             ?? inJson.mo             ?? null;

const month_name = (mo >= 1 && mo <= 12) ? monthNames[mo - 1] : null;
const month_name_abbr = (mo >= 1 && mo <= 12) ? monthAbbr[mo - 1] : null;

// 3) Normalizar empleados SIN perder campos
const empleadosOut = [];

for (let i = 0; i < empleadosIn.length; i++) {
  const empRaw = empleadosIn[i];

  // Partir del objeto completo para NO perder campos
  const e = { ...(empRaw ?? {}) };

  // ✅ Materializar idx (lo que antes era $itemIndex/meta)
  e.idx = pickIdx(e, i);
  e.idx_1b = e.idx + 1;

  // ✅ Identificación: tomar de varias llaves ANTES de normalizar, y no pisar con vacío
  const idSrc =
    e.identificacion ??
    e.cedula ??
    e['Cédula'] ??
    e['CEDULA'] ??
    e.id ??
    e.identificación ??
    null;

  const idNorm = normCedula(idSrc);
  if (idNorm) e.identificacion = idNorm;
  e._id_source = idSrc;

  // Asegurar empresa (si vino null)
  if (e.empresa === undefined || e.empresa === null || e.empresa === '') {
    e.empresa = empresa;
  }

  // Asegurar clave (si falta)
  if (!e.clave || String(e.clave).trim() === '') {
    e.clave = (e.empresa && e.identificacion) ? `${e.empresa}-${e.identificacion}` : (e.clave ?? null);
  }

  // --- FR: mapear y derivar fr_modo, SIN sobreescribir datos base
  e.fr_sucursal = e.fr_sucursal ?? e.sucursal ?? null;
  e.fr_aportes_periodo = e.fr_aportes_periodo ?? e.aportes_periodo ?? null;
  e.fr_fecha_solicitud = e.fr_fecha_solicitud ?? null;

  if (SWAP_DER_CARGOS) {
    const tmp = e.fr_derecho;
    e.fr_derecho = e.fr_tiene_cargos;
    e.fr_tiene_cargos = tmp;
  }

  const fr_derecho = truthy(e.fr_derecho);
  const fr_acumulacion = truthy(e.fr_acumulacion);
  e.fr_modo = frModo(fr_derecho, fr_acumulacion);

  // --- Quiro: crear alias iess_quiro_* sin borrar monto_quiro/quiro_*
  e.iess_quiro_monto  = toNum(e.iess_quiro_monto ?? e.monto_quiro ?? 0);
  e.iess_quiro_nuts   = emptyToNull(e.iess_quiro_nuts ?? e.quiro_nuts ?? null);
  e.iess_quiro_origen = emptyToNull(e.iess_quiro_origen ?? e.quiro_origen ?? null);

  // --- Números clave: salario_base puede venir como db_salario_base
  const salarioBaseSrc = (e.salario_base ?? e.db_salario_base ?? null);
  if (salarioBaseSrc !== null && salarioBaseSrc !== undefined && salarioBaseSrc !== '') {
    e.salario_base = toNum(salarioBaseSrc);
  }

  // ✅ Rubros típicos: normalizar numéricos SIN destruir el original
  // (esto ayuda a evitar “no capturó” cuando aguas abajo esperan números)
  e.sueldo_variable_num = toNum(e.sueldo_variable ?? e.db_sueldo_variable ?? 0);
  e.otros_ingresos_num  = toNum(e.otros_ingresos ?? e.db_otros_ingresos ?? 0);
  e.transporte_num      = toNum(e.transporte ?? e.db_transporte ?? 0);
  e.movilizacion_num    = toNum(e.movilizacion ?? e.db_movilizacion ?? 0);
  e.compensacion_num    = toNum(e.compensacion ?? e.db_compensacion ?? 0);
  e.utilidades_num      = toNum(e.utilidades ?? e.db_utilidades ?? 0);
  e.anticipos_num       = toNum(e.anticipos ?? e.db_anticipos ?? 0);
  e.prestamos_empresa_num = toNum(e.prestamos_empresa ?? e.db_prestamos_empresa ?? 0);

  // valor_alimentacion_4_5: mantener boolean
  if (e.valor_alimentacion_4_5 !== undefined && e.valor_alimentacion_4_5 !== null) {
    e.valor_alimentacion_4_5 = truthy(e.valor_alimentacion_4_5);
  }

  // --- Filtro anti-fantasmas (más tolerante)
  const nombre = String(e.nombre ?? e.db_nombre ?? '').trim();
  const hasNombre = nombre.length > 0;

  // salario puede venir como salario_base o db_salario_base
  const hasSalario = toNum(e.salario_base ?? e.db_salario_base ?? 0) > 0;

  // en_db puede venir como true/"true"/1/"1"
  const isEnDb = truthy(e.en_db);

  if (!hasNombre && !hasSalario && !isEnDb) continue;

  // Asegurar nombre (prioriza nombre, luego db_nombre)
  if (!e.nombre || String(e.nombre).trim() === '') {
    e.nombre = nombre; // ya viene de nombre o db_nombre
  }

  // --- Auditoría opcional para debug (puedes borrar luego)
  // Te dice si se perdió algo (normalmente no) y cómo quedó la identificación
  const beforeKeys = Object.keys(empRaw ?? {});
  const afterKeys  = Object.keys(e);
  e._audit = {
    missing_keys: beforeKeys.filter(k => !(k in e)),
    id_before: empRaw?.identificacion ?? empRaw?.cedula ?? empRaw?.['Cédula'] ?? null,
    id_after: e.identificacion ?? null,
    clave: e.clave ?? null,
  };

  empleadosOut.push(e);
}

// 4) Salida: 1 item (lote) listo para Excel
const lote = {
  empresa,
  fecha_nomina,
  periodo_key,
  periodo_inicio,
  periodo_fin,
  y,
  mo,
  month_name,
  month_name_abbr,
  empleados: empleadosOut,
};

return [{ json: lote }];

// Entrada: muchos items { identificacion, tipo, valor }
// Salida: 1 item { descuentos: { <cedula>: { multa, crediflash, saludsa, seguro_accidentes, anticipos, prestamos } } }

const map = {};

for (const it of items) {
  const { identificacion, tipo, valor } = it.json || {};
  if (!identificacion || !tipo) continue;
  if (!map[identificacion]) map[identificacion] = {};
  map[identificacion][tipo] = (map[identificacion][tipo] || 0) + (Number(valor) || 0);
}

return [{ json: { descuentos: map } }];

// Junta todas las claves que aparecen en algún item
const allKeys = new Set();
for (const { json } of items) {
  for (const k of Object.keys(json)) allKeys.add(k);
}

// Helper para ubicar la columna de cédula
const norm = s => (s ?? '')
  .toString()
  .normalize('NFD').replace(/[\u0300-\u036f]/g,'')
  .toLowerCase().trim();

return items.map(({ json }) => {
  const j = { ...json };

  // identificacion limpia (solo dígitos) desde la columna que contenga "cédula"
  const keyCed = Object.keys(j).find(k => norm(k).includes('cedula')) || '';
  const ced = keyCed ? String(j[keyCed] ?? '').replace(/\D/g, '') : '';
  j.identificacion = ced;

  // Relleno: cualquier campo ausente/undefined/null/'' -> 0
  for (const k of allKeys) {
    const v = j[k];
    if (
      v === undefined ||
      v === null ||
      (typeof v === 'string' && v.trim() === '') ||
      (typeof v === 'string' && v.toLowerCase() === 'undefined') // por si venía como texto
    ) {
      j[k] = 0;
    }
  }

  return { json: j };
});

/**
 * SET PERIODO (única fuente de fecha del flujo)
 * Lee fecha_nomina del Webhook (multipart/form-data => body.fecha_nomina)
 * Acepta: '2025-06', '2025-06-30', '202506', 'Junio 2025', 'jun-25', '2025 junio', etc.
 * Devuelve: fecha_nomina (último día), periodo_key (YYYYMM), periodo_inicio, periodo_fin, y, mo
 */

// 1) Tomar la fecha del Webhook desde donde venga
const rawInput =
  ($json?.body?.fecha_nomina) ??    // típico con curl.exe -F ...
  ($json?.query?.fecha_nomina) ??   // por si la mandan en la URL ?fecha_nomina=...
  ($json?.fecha_nomina) ??          // si llegase como JSON plano
  '';

const raw = String(rawInput).trim();
if (!raw) {
  throw new Error('fecha_nomina no llegó en el Webhook. Envía -F "fecha_nomina=2025-06".');
}

// 2) Diccionario de meses en español
const MONTHS = {
  enero:1, febrero:2, marzo:3, abril:4, mayo:5, junio:6,
  julio:7, agosto:8, septiembre:9, setiembre:9, octubre:10, noviembre:11, diciembre:12,
  ene:1, feb:2, mar:3, abr:4, may:5, jun:6, jul:7, ago:8, sep:9, oct:10, nov:11, dic:12
};
const MONTHS_NUM_TO_NAME = ['','enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

// 3) Parser robusto
function parsePeriodo(s){
  s = s.toLowerCase().replace(',', ' ').trim();

  // YYYYMM (6 dígitos)
  let m = s.match(/^(\d{4})(\d{2})$/);
  if (m) return { y: +m[1], mo: +m[2] };

  // YYYY-MM(-DD)? o YYYY/MM(/DD)? o con espacios
  m = s.match(/^(\d{4})[-/.\s](\d{1,2})(?:[-/.\s]\d{1,2})?$/);
  if (m) return { y: +m[1], mo: +m[2] };

  // "Junio 2025", "jun-25", "2025 junio"
  const tokens = s.split(/[-/.\s]+/).filter(Boolean); // ej: ["junio","2025"] o ["jun","25"]
  const tokYear4 = tokens.find(t => /^\d{4}$/.test(t));
  const tokYear2 = tokens.find(t => /^\d{2}$/.test(t));
  const year = tokYear4 ? +tokYear4
            : tokYear2 ? +(String(new Date().getFullYear()).slice(0,2) + tokYear2)
            : null;

  const tokMonth = tokens.find(t => MONTHS[t] !== undefined);
  if (year && tokMonth) return { y: year, mo: MONTHS[tokMonth] };

  throw new Error(`No pude interpretar fecha_nomina: "${s}"`);
}

// 4) Cálculos del periodo
const { y, mo } = parsePeriodo(raw);
if (!(mo >= 1 && mo <= 12)) throw new Error(`Mes fuera de rango: ${mo}`);

function pad(n){ return (n < 10 ? '0' : '') + n; }
function lastDayOfMonth(year, month /*1..12*/){ return new Date(year, month, 0).getDate(); }

const diaFin = lastDayOfMonth(y, mo);
const periodo_inicio = `${y}-${pad(mo)}-01`;
const fecha_nomina   = `${y}-${pad(mo)}-${pad(diaFin)}`; // último día del mes
const periodo_fin    = fecha_nomina;
const periodo_key    = `${y}${pad(mo)}`;

// 5) Salida (un solo item)
return [
  {
    json: {
      fecha_nomina,        // p.ej. "2025-06-30"
      periodo_key,         // "202506"
      periodo_inicio,      // "2025-06-01"
      periodo_fin,         // "2025-06-30"
      y,                   // 2025
      mo,                  // 6
      month_name: MONTHS_NUM_TO_NAME[mo],   // "junio" (útil para reportes)
      month_name_abbr: MONTHS_NUM_TO_NAME[mo].slice(0,3) // "jun"
    }
  }
];

// INPUT: items[*].json.text con el texto del PDF (una o varias páginas/items)
// OUTPUT: una lista de items { cedula, nombre, sucursal, fr_tiene_solicitud, fr_tiene_cargos, fr_derecho, fr_acumulacion, fr_fecha_solicitud, aportes_periodo }

const raw = items.map(it => (it?.json?.text || '')).join('\n').toString();

// Limpieza + normalización
let txt = raw
  .replace(/\u00a0/g, ' ')          // NBSP
  .replace(/\r/g, '')
  .replace(/\f/g, '\n')
  .replace(/[ \t]+/g, ' ')
  .replace(/Page\s+\d+\s+of.*$/gmi, '')
  .replace(/Página\s+\d+\s+de.*$/gmi, '')
  .replace(/SÍ/gmi, 'SI')
  .trim();

// Periodo de aportes
let aportes_periodo = null;
const mPer = txt.match(/CALIFICACION DE DERECHO FR CON APORTES DE:\s*([A-ZÁÉÍÓÚÑ\/0-9]+)/i);
if (mPer) aportes_periodo = mPer[1].trim();

// Regex robusto (igual que el que te funcionó)
const re = /(?<id>(?<!\d)\d{9,10}(?!\d))\s+(?<nombre>[\s\S]*?)\s*(?<sucursal>\d{4})\s+(?<sol>SI|NO)\s+(?<jam>(?:SI|NO)\s*(?:SI|NO))(?<fecha>\d{2}\/\d{2}\/\d{2})?/gmi;

const results = [];
let m;

while ((m = re.exec(txt)) !== null) {
  // Cédula siempre 10 dígitos (si viene 9, rellena a la izquierda)
  const cedula = String(m.groups.id).slice(-10).padStart(10, '0');

  let nombre = (m.groups.nombre || '')
    .replace(/\n+/g, ' ')
    .replace(/\s{2,}/g, ' ')
    .trim();

  const sucursal = m.groups.sucursal || null;
  const tieneSolicitud = (m.groups.sol || '').toUpperCase() === 'SI';

  const jamClean = (m.groups.jam || '').replace(/\s+/g, '').toUpperCase();
  const x1 = jamClean.slice(0, 2); // DERECHO
  const x2 = jamClean.slice(2, 4); // CARGOS

  const fr_derecho = x1 === 'SI';
  const fr_tiene_cargos = x2 === 'SI';

  const fr_fecha_solicitud = m.groups.fecha || null;

  results.push({
    cedula,
    nombre,
    sucursal,
    fr_tiene_solicitud: tieneSolicitud,
    fr_tiene_cargos: fr_tiene_cargos,
