// Toma el texto plano que entregó "Extract from File"
const txt = $json.text || "";

// Helpers
const pick = (re) => {
  const m = txt.match(re);
  return m ? m[1].trim() : null;
};

// Encabezados (agarra la primera coincidencia, el PDF repite cabecera en la 2da página)
const empresa       = pick(/Nombre o Razón Social de la Empresa:\s*([\s\S]*?)\n/i);
const ruc           = pick(/R\.U\.C:\s*([\d-]+)/i);
const periodo       = pick(/Periodo:\s*\n?(\d+)/i);
const fechaMaxPago  = pick(/Fecha Max\. de pago:\s*\n?([0-9/]+)/i);
const representante = pick(/Apellidos y Nombre.*?\n([^\n]+)/i);
const totalReportado= pick(/(\d[\d.,]*)\s*\nTotal:/i);

// Filas de detalle:  N°  CEDULA(10)  NOMBRE(S)  NUT  VALOR
// Ej.: "1 1721807046 AVEIGA AVEIGA CARLOS LUIS 16830227 96.43"
const lineRE = /^\s*\d+\s+(\d{10})\s+(.+?)\s+(\d+)\s+(\d+(?:\.\d{2})?)\s*$/u;

const rows = [];
for (const raw of txt.split(/\r?\n/)) {
  const line = raw.trim();
  const m = line.match(lineRE);
  if (m) {
    rows.push({
      cedula: m[1],
