}

// (Opcional) suma para validar con el “Total” del PDF
const suma = rows.reduce((a, r) => a + (r.valor || 0), 0);

// Devuelve un item por fila, incluyendo los metadatos del encabezado
return rows.map(r => ({
  json: {
    ...r,
    empresa,
    ruc,
    periodo: periodo ? Number(periodo) : null,
    fechaMaxPago,
    representante,
    totalReportado,
    sumaCalculada: Number(suma.toFixed(2)),
  }
}));

// === Code (JavaScript) — Pick mes (descuentos) ===
// Run once for all items: ON
//
// Entrada: filas de descuentos (unidas de todas las hojas) con campo `_tipo` + columnas por mes.
// Salida: un item por fila: { identificacion, tipo, valor } del mes seleccionado.

// 1) Leer periodo (y/mo) del nodo de fecha, por nombre (independiente del puerto)
const PERIOD_CANDIDATES = ['set periodo', 'Set periodo', 'Code in JavaScript3', 'Code in JavaScript 3'];
let periodo = null;

for (const name of PERIOD_CANDIDATES) {
  try {
    const arr = $items(name);
    if (arr?.length && arr[0]?.json?.y && arr[0]?.json?.mo) {
      periodo = arr[0].json;
      break;
    }
  } catch (_) {}
}
if (!periodo) {
  // intento alterno por $node[...] (por si tu versión lo permite)
  try { periodo = $node['Periodo nomina'].json; } catch(_) {}
}
if (!periodo?.y || !periodo?.mo) {
  throw new Error('No pude leer y/mo desde "set periodo". Ejecuta ese nodo antes o revisa el nombre.');
}
const y  = periodo.y;                 // 2025
const mo = periodo.mo;                // 6
const mm = String(mo).padStart(2,'0');

// 2) Utilidades
const MES = ['','enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const ABB = ['','ene','feb','mar','abr','may','jun','jul','ago','sep','oct','nov','dic'];
const mesL = MES[mo];
const mesS = ABB[mo];
const y2   = String(y).slice(2);

const normalize = (s) =>
  (s ?? '')
    .toString()
    .normalize('NFD').replace(/\p{Diacritic}/gu,'')
    .toLowerCase()
    .replace(/\s+/g,' ')
    .trim();

function toNumber(v){
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  let s = String(v).trim().replace(/[^\d.,-]/g,'');
  const lc = s.lastIndexOf(','), ld = s.lastIndexOf('.');
  if (lc > ld) s = s.slice(0, lc).replace(/[^\d-]/g,'') + '.' + s.slice(lc+1).replace(/\D/g,'');
  else if (ld > lc) s = s.slice(0, ld).replace(/[^\d-]/g,'') + '.' + s.slice(ld+1).replace(/\D/g,'');
  else s = s.replace(/[^\d-]/g,'');
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}
const onlyDigits = (s) => (s ?? '').toString().replace(/\D/g,'');

// targets del encabezado que podrían representar el mes actual
const targets = new Set([
  `${y}-${mm}`, `${y}/${mm}`, `${y} ${mm}`,
  `${mm}-${y}`, `${mm}/${y}`, `${mm} ${y}`,
  `${y}${mm}`,
  `${mesL} ${y}`, `${mesS} ${y}`,
  `${y} ${mesL}`, `${y} ${mesS}`,
  `${mesS}-${y2}`, `${mesS}${y2}`,
  `${mm}-${y2}`, `${mm}${y2}`,
]);

function headerMatches(h){
  const nh = normalize(h);
  if (targets.has(nh)) return true;
  if (nh.includes(String(y)) && (nh.includes(mesL) || nh.includes(mesS) || nh.includes(mm) || nh.includes(String(mo)))) return true;
  const digits = nh.replace(/\D/g,'');
  return digits === `${y}${mm}`;
}

// 3) Procesar filas
const out = [];

for (const it of items) {
  const row = it.json || {};

  // toma tipo etiquetado en los Set previos (Edit Fields3..8)
  const tipo = (row._tipo ?? row.tipo ?? '').toString().trim().toLowerCase();

  // identifica cédula en distintas variantes
  const id = onlyDigits(row.identificacion ?? row.cedula ?? row['cédula'] ?? row.ci ?? row.dni);

  // si viene un item “extra” (p.ej. del Merge2 en Append), lo ignoramos
  if (!tipo || !id) continue;

  // localizar la columna del mes
  const keys = Object.keys(row).filter(k =>
    !['_tipo','tipo','identificacion','cedula','cédula','ci','dni','nombre'].includes(k)
  );

  let valor = 0;
  for (const k of keys) {
    if (headerMatches(k)) { valor = toNumber(row[k]); break; }
  }

  out.push({ json: { identificacion: id, tipo, valor } });
}

return out;

// Agrupa por cédula y suma valores
const items = $input.all(); // viene del Function anterior (uno por fila)

const byId = new Map();

for (const { json } of items) {
  const key = json.cedula;
  if (!byId.has(key)) {
    byId.set(key, {
      cedula: key,
      nombres: json.nombres,
      // metadatos útiles (repiten por cada fila, tomamos la primera vez)
      empresa: json.empresa,
      ruc: json.ruc,
      periodo: json.periodo,
      fechaMaxPago: json.fechaMaxPago,
      representante: json.representante,
      totalReportado: json.totalReportado ?? null,
      // acumuladores
      total: 0,
      detalle: [],      // lista de { nut, valor }
      nuts: [],         // solo los NUTs si los quieres aparte
      items: 0          // cuántas líneas aportó esta cédula
    });
  }

  const acc = byId.get(key);
  const v = Number(json.valor || 0);

  acc.detalle.push({ nut: json.nut, valor: v });
  acc.nuts.push(json.nut);
  acc.total = Number((acc.total + v).toFixed(2));
  acc.items += 1;
}

// Devolvemos un item por persona (cédula)
return Array.from(byId.values()).map(p => ({ json: p }));

/**
 * n8n Code node — Limpieza/normalización final para nómina
 * - Prioridad de rubros: *_fix > archivo > campo normal > db_*
 * - Prorratea sueldo base por días trabajados: (salario_mensual/30)*dias_trabajados
 * - Mantiene décimos igual (según tu pedido)
 */
const APPLY_DEDUCCION_ATRASOS_Y_FALTAS = true;
const IESS_PERSONAL_PCT = 0.0945;   // 9.45%
const FONDO_RESERVA_PCT = 0.0833;   // 8.33%
const SUELDO_BASICO_DEC14 = 470;    // se mantiene igual

function isPresent(v) {
  return v !== null && v !== undefined && v !== '' && v !== '-' && !(typeof v === 'number' && Number.isNaN(v));
}

function toNumber(v, def = 0) {
  if (!isPresent(v)) return def;
  if (typeof v === 'number') return Number.isFinite(v) ? v : def;

  let s = String(v).trim();
  const hasComma = s.includes(',');
  const hasDot = s.includes('.');

  if (hasComma && !hasDot) s = s.replace(',', '.');
  if (hasComma && hasDot) s = s.replace(/,/g, '');

  const n = parseFloat(s);
  return Number.isFinite(n) ? n : def;
}

function round2(n) {
  return Math.round((n + Number.EPSILON) * 100) / 100;
}

function pickFirst(...vals) {
  for (const v of vals) if (isPresent(v)) return v;
  return null;
}

function sumNumbers(...vals) {
  return round2(vals.reduce((acc, v) => acc + toNumber(v, 0), 0));
}

/**
 * Extrae rubros y calcula:
 * - salario_mensual (FULL)
 * - dias_trabajados (prioridad fix -> input -> excel -> 30)
 * - salario_base (PAGABLE prorrateado)
 */
function extractRubros(e) {
  // ✅ Salario mensual FULL (contrato/DB/Excel)
  const salario_mensual = round2(toNumber(pickFirst(
    e.salario_base,
    e.db_salario_base,
    e.SUELDO,
    e['SUELDO']
  ), 0));

  // ✅ DÍAS TRABAJADOS (FIX primero, luego input normalizado, luego Excel, luego default)
  const dias_trabajados = round2(toNumber(pickFirst(
    e.dias_trabajados_fix,
    e.dias_trabajados,
    e['Días Trabajados'],
    e['DIAS TRABAJADOS'],
    30
  ), 30));

  // ✅ Tarifa diaria basada en salario mensual
  const daily_rate_mensual = salario_mensual > 0 ? (salario_mensual / 30) : 0;

  // ✅ Salario base PAGABLE (prorrateado por días trabajados)
  const salario_base = round2(daily_rate_mensual * dias_trabajados);

  const sueldo_variable = round2(toNumber(pickFirst(
    e.sueldo_variable_fix,
    e['SUELDO VARIABLE-1032'],
    e['SUELDO VARIABLE'],
    e.sueldo_variable,
    e.db_sueldo_variable
  ), 0));

  const transporte = round2(toNumber(pickFirst(
    e.transporte_fix,
    e['TRANSPORTE - 1050'],
    e['TRANSPORTE-1050'],
    e.transporte,
    e.db_transporte
  ), 0));

  const movilizacion = round2(toNumber(pickFirst(
    e.movilizacion_fix,
    e['MOVILIZACION - 1042'],
    e['MOVILIZACION-1042'],
    e.movilizacion,
    e.db_movilizacion
  ), 0));

  const otros_ingresos = round2(toNumber(pickFirst(
    e.otros_ingresos_fix,
    e['OTROS INGRESOS'],
    e['OTROS INGRESOS-2183'],
    e.otros_ingresos,
    e.db_otros_ingresos
  ), 0));

  const compensacion = round2(toNumber(pickFirst(
    e.compensacion_fix,
    e['COMPENSACION'],
    e.compensacion,
    e.db_compensacion
  ), 0));

  const utilidades = round2(toNumber(pickFirst(
    e.utilidades_fix,
    e.utilidades,
    e.db_utilidades
  ), 0));

  // Horas extras (horas)
  const he50_horas = round2(toNumber(pickFirst(
    e.he50_horas,
    e['HE 50% CANTIDAD'],
    e['HE50 CANTIDAD'],
    e['50%']
  ), 0));

  const he100_horas = round2(toNumber(pickFirst(
    e.he100_horas,
    e['HE 100% CANTIDAD'],
    e['HE100 CANTIDAD'],
    e['100%']
  ), 0));

  /**
   * ✅ IMPORTANTE:
   * La tarifa por hora conviene basarla en el salario mensual FULL (contrato),
   * aunque el sueldo del mes se pague prorrateado.
   */
  const hora_base = salario_mensual > 0 ? (daily_rate_mensual / 8) : 0;
  const he50_valor = round2(toNumber(pickFirst(e.he50_valor), 0) || (he50_horas * hora_base * 1.5));
  const he100_valor = round2(toNumber(pickFirst(e.he100_valor), 0) || (he100_horas * hora_base * 2));

  // Alimentación
  const alimentacion_dias = round2(toNumber(pickFirst(
    e.dias_alimentacion_fix,
    e.alimentacion_dias,
    e['ALIMENTACION'],
    e['Alimentación'],
    e['DIAS ALIMENTACION']
  ), 0));

  const tarifa_45 = Boolean(pickFirst(e.valor_alimentacion_4_5, e.db_valor_alimentacion_4_5));
  const alimentacion_tarifa = tarifa_45 ? 4.5 : 2.5;
  const alimentacion_valor = round2(alimentacion_dias * alimentacion_tarifa);

  // Atrasos y faltas
  const atrasos_dias = round2(toNumber(pickFirst(
    e.atrasos_dias,
    e['Días a descontar por ATRASOS'],
    e['DIAS A DESCONTAR POR ATRASOS'],
    0
  ), 0));

  const faltas = round2(toNumber(pickFirst(
    e.faltas,
    e['Total Faltas'],
    e['TOTAL FALTAS'],
    e['Faltas Injst.'],
    0
  ), 0));

  return {
    // ✅ ambos: FULL y PAGABLE
    salario_mensual,
    salario_base, // prorrateado (pagable)

    sueldo_variable,
    transporte,
    movilizacion,
    otros_ingresos,
    compensacion,
    utilidades,

    he50_horas,
    he50_valor,
    he100_horas,
    he100_valor,

    alimentacion_dias,
    alimentacion_tarifa,
    alimentacion_valor,

    dias_trabajados,
    atrasos_dias,
    faltas,

    hora_base: round2(hora_base),
    daily_rate_mensual: round2(daily_rate_mensual)
  };
}

function computeFondoReserva(e, total_ingresos_iess) {
  const derecho = Boolean(e.fr_derecho);
  const modo = e.fr_modo || (derecho ? 'paga' : 'sin_derecho');

  const fix = isPresent(e.fondo_reserva_fix) ? toNumber(e.fondo_reserva_fix, null) : null;

  if (!derecho) {
    return { derecho: false, modo: 'sin_derecho', calculado: 0, pagado: 0, acumulado: 0, fix_usado: false };
  }

  const calculado = round2((fix !== null ? fix : (total_ingresos_iess * FONDO_RESERVA_PCT)));
  const paga = modo === 'paga';
  return {
    derecho: true,
    modo,
    calculado,
    pagado: paga ? calculado : 0,
    acumulado: paga ? 0 : calculado,
    fix_usado: fix !== null
  };
}

function processEmployee(e) {
  const r = extractRubros(e);

  // ✅ Base IESS: aportables (ya con salario_base prorrateado)
  const total_ingresos_iess = sumNumbers(
    r.salario_base,        // ✅ prorrateado
    r.sueldo_variable,
    r.transporte,
    r.movilizacion,
    r.otros_ingresos,
    r.he50_valor,
    r.he100_valor
  );

  const total_no_aportables = sumNumbers(r.alimentacion_valor, r.compensacion);
  const utilidades_no_aportables = r.utilidades;

  const ingresos_pagables = sumNumbers(total_ingresos_iess, total_no_aportables, utilidades_no_aportables);

  // ✅ Décimos: se mantienen igual
  const decimos_mensual = Boolean(pickFirst(e.db_decimos_mensual, e.decimos_mensual, true));
  const decimo_13 = decimos_mensual ? round2(total_ingresos_iess / 12) : 0;

  const dias_dec14 = isPresent(r.dias_trabajados) ? r.dias_trabajados : 30;
  const decimo_14 = decimos_mensual ? round2((SUELDO_BASICO_DEC14 / 360) * dias_dec14) : 0;

  const fondo_reserva = computeFondoReserva(e, total_ingresos_iess);

  // Descuentos
  const d0 = e.descuentos || {};
  const anticipos = round2(toNumber(pickFirst(e.desc_anticipos, d0.anticipos, e.db_anticipos), 0));
  const prestamos_empresa = round2(toNumber(pickFirst(e.desc_prestamos, d0.prestamos_empresa, e.db_prestamos_empresa), 0));
  const crediflash = round2(toNumber(pickFirst(e.desc_crediflash, d0.crediflash, e.db_crediflash), 0));
  const saludsa = round2(toNumber(pickFirst(e.desc_saludsa, d0.saludsa, e.db_saludsa), 0));
  const seguro_accidentes = round2(toNumber(pickFirst(e.desc_seguro_accidentes, d0.seguro_accidentes), 0));
  const multa = round2(toNumber(pickFirst(e.desc_multa, d0.multa), 0));

  const iess_quiro_monto = round2(toNumber(pickFirst(
    e.iess_quiro_monto,
    d0.iess_quiro_monto,
    e.monto_quiro
  ), 0));

  // ✅ deducción días: usar daily_rate del salario mensual (no del prorrateado)
  const daily_rate = r.daily_rate_mensual || round2(r.salario_mensual / 30);
  const deduccion_dias = APPLY_DEDUCCION_ATRASOS_Y_FALTAS
    ? round2(daily_rate * (r.faltas + r.atrasos_dias))
    : round2(toNumber(pickFirst(d0.deduccion_dias, e.deduccion_dias), 0));

  const ap_pers_iess = round2(total_ingresos_iess * IESS_PERSONAL_PCT);

  const total_descuentos = sumNumbers(
    anticipos,
    prestamos_empresa,
    crediflash,
    saludsa,
    seguro_accidentes,
    multa,
    iess_quiro_monto,
    deduccion_dias,
    ap_pers_iess
  );

  const descuentos = {
    anticipos,
    prestamos_empresa,
    crediflash,
    saludsa,
    seguro_accidentes,
    multa,
    iess_quiro_monto,
    deduccion_dias,
    ap_pers_iess,
    total_descuentos
  };

  const bruto_recibir = sumNumbers(ingresos_pagables, decimo_13, decimo_14, fondo_reserva.pagado);
  const valor_final_recibir = round2(bruto_recibir - total_descuentos);

  const costo_empleador = sumNumbers(ingresos_pagables, decimo_13, decimo_14, fondo_reserva.calculado);

  return {
    ...e,

    // ✅ sueldo full y sueldo prorrateado visibles
    salario_mensual: r.salario_mensual,
    salario_base: r.salario_base, // prorrateado (pagable)

    sueldo_variable: r.sueldo_variable,
    transporte: r.transporte,
    movilizacion: r.movilizacion,
    utilidades: r.utilidades,
    otros_ingresos: r.otros_ingresos,
    compensacion: r.compensacion,

    he50_horas: r.he50_horas,
    he50_valor: r.he50_valor,
    he100_horas: r.he100_horas,
    he100_valor: r.he100_valor,

    alimentacion_dias: r.alimentacion_dias,
    alimentacion_tarifa: r.alimentacion_tarifa,
    alimentacion_valor: r.alimentacion_valor,

    dias_trabajados: r.dias_trabajados,

    ingresos: {
      salario_base: r.salario_base, // ✅ prorrateado
      sueldo_variable: r.sueldo_variable,
      transporte: r.transporte,
      movilizacion: r.movilizacion,
      utilidades: r.utilidades,
      otros_ingresos: r.otros_ingresos,
      he50_valor: r.he50_valor,
      he100_valor: r.he100_valor,
      alimentacion_valor: r.alimentacion_valor,
      compensacion: r.compensacion,

      total_no_aportables,
      total_ingresos_iess,
      ingresos_pagables
    },

    decimos: {
      mensual: decimos_mensual,
      decimo_13: round2(decimo_13),
      decimo_14: round2(decimo_14)
    },

    fondo_reserva,
    descuentos,

    valor_final_recibir,
    costo_empleador,

    _calc_meta: {
      hora_base: r.hora_base,
      daily_rate_mensual: r.daily_rate_mensual,
      salario_mensual: r.salario_mensual,
      salario_base_prorrateado: r.salario_base,
      dias_trabajados_fix: toNumber(e.dias_trabajados_fix, 0),
      dias_trabajados_input: toNumber(e.dias_trabajados, 0),
      dias_trabajados_excel: toNumber(e['Días Trabajados'], 0),
      faltas: r.faltas,
      atrasos_dias: r.atrasos_dias
    }
  };
}

/**
 * Entrada:
 *  A) [{ json: { ... meta ..., empleados:[...] } }]
 *  B) [{ json: { ... empleado ... } }, ...]
 */
const items = $input.all();

return items.map(item => {
  const j = item.json;

  if (Array.isArray(j.empleados)) {
    const empleados = j.empleados.map(processEmployee);
    return { json: { ...j, empleados } };
  }

  return { json: processEmployee(j) };
});

// === Code (JavaScript) — Preparar filas para Excel (nómina_detalle) ===
// Run once for all items: ON

// 1) Validación de entrada
if (!items?.length || !items[0]?.json) {
