// 2) Helper para redondeo y limpieza numérica
const r2 = (x) => Math.round((Number(x) + Number.EPSILON) * 100) / 100;
const numOr0 = (v) => (typeof v === 'number' ? v : Number(v || 0));

// Helper para normalizar texto (orden alfabético consistente, sin tildes)
const normText = (v) =>
  String(v ?? '')
    .trim()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '') // quita tildes
    .toUpperCase();

// 3) Definimos orden de columnas del Excel (puedes ajustar sin romper nada)
const COLS = [
  'empresa','periodo_key','fecha_nomina','periodo_inicio','periodo_fin',
  'identificacion','nombre','estado','dias_trabajados','faltas_injustificadas','atrasos_dias','fs_feriado',
  'salario_base','sueldo_variable','transporte','movilizacion','utilidades','otros_ingresos',
