  'alimentacion_dias','alimentacion_tarifa','alimentacion_valor','compensacion',
  'total_no_aportables','total_ingresos_iess','ingresos_pagables',
  'decimo_13','decimo_14',
  'fr_derecho','fr_modo','fr_calculado','fr_pagado','fr_acumulado',
  'anticipos','prestamos_empresa','crediflash','saludsa','seguro_accidentes','iess_quiro_monto',
  'deduccion_dias','ap_pers_iess','total_descuentos',
  'valor_final_recibir','costo_empleador'
];

// 4) Orden alfabético del personal (por nombre; fallback por identificación)
const empleadosOrdenados = [...lote.empleados].sort((a, b) => {
  const an = normText(a?.nombre);
  const bn = normText(b?.nombre);

  // Si ambos tienen nombre, ordena por nombre
  if (an && bn) {
    const c = an.localeCompare(bn, 'es', { sensitivity: 'base' });
    if (c !== 0) return c;
  } else if (an || bn) {
    // Si solo uno tiene nombre, ese va primero
    return an ? -1 : 1;
  }

  // Desempate / fallback: identificación
  const ai = normText(a?.identificacion);
  const bi = normText(b?.identificacion);
  return ai.localeCompare(bi, 'es', { sensitivity: 'base' });
});

// 5) Transformación: empleado -> fila Excel
const filas = empleadosOrdenados.map((e) => {
  const ing  = e.ingresos || {};
  const dec  = e.decimos || {};
  const fr   = e.fondo_reserva || {};
  const desc = e.descuentos || {};
  const alimMeta = e._alim_meta || {};
  const calcMeta = e._calc_meta || {};

  // === Asistencias / días ===
  // Usamos el valor ya calculado por el nodo de nómina (que respeta dias_trabajados_fix)
  const diasTrabajados = (typeof e.dias_trabajados === 'number' && !Number.isNaN(e.dias_trabajados))
    ? e.dias_trabajados
    : 30;

  // Faltas / atrasos:
  //  - Preferimos campos directos si existen
  //  - Si no, usamos los que vienen en _calc_meta (los calculó el nodo de nómina)
  const faltasInj = (typeof e.faltas_injustificadas === 'number')
    ? e.faltas_injustificadas
    : (typeof calcMeta.faltas === 'number' ? calcMeta.faltas : 0);

  const atrasosDias = (typeof e.atrasos_dias === 'number')
    ? e.atrasos_dias
    : (typeof calcMeta.atrasos_dias === 'number' ? calcMeta.atrasos_dias : 0);

  // === Alimentación ===
  //  - días: los que realmente se usaron en el cálculo (después de fix/clamp)
  //  - tarifa: la tarifa usada en el cálculo (2.5 o 4.5)
  const alimDiasUsados =
    (typeof alimMeta.dias_usados === 'number' && !Number.isNaN(alimMeta.dias_usados))
      ? alimMeta.dias_usados
      : numOr0(e.alimentacion_dias);

  const alimTarifaUsada =
    (typeof alimMeta.tarifa_usada === 'number' && !Number.isNaN(alimMeta.tarifa_usada))
      ? alimMeta.tarifa_usada
      : (e.valor_alimentacion_4_5 === true ? 4.50 : 2.50);

  const fila = {
    // Contexto del periodo (repetido por fila para pivotar/filtros en Excel)
    empresa: lote.empresa || '',
    periodo_key: lote.periodo_key || '',
    fecha_nomina: lote.fecha_nomina || '',
    periodo_inicio: lote.periodo_inicio || '',
    periodo_fin: lote.periodo_fin || '',

    // Identificación
    identificacion: e.identificacion || '',
    nombre: e.nombre || '',
    estado: e.estado || '',

    // Asistencias / marcaciones
    dias_trabajados: r2(numOr0(diasTrabajados)),
    faltas_injustificadas: r2(numOr0(faltasInj)),
    atrasos_dias: r2(numOr0(atrasosDias)),
    fs_feriado: r2(numOr0(e.fs_feriado)),

    // Ingresos base
    salario_base: r2(numOr0(ing.salario_base)),
    sueldo_variable: r2(numOr0(ing.sueldo_variable)),
    transporte: r2(numOr0(ing.transporte)),
    movilizacion: r2(numOr0(ing.movilizacion)),
    utilidades: r2(numOr0(ing.utilidades)),
    otros_ingresos: r2(numOr0(ing.otros_ingresos)),

    // Horas extra
    he50_horas: r2(numOr0(e.he50_horas)),
    he50_valor: r2(numOr0(ing.he50_valor)),
    he100_horas: r2(numOr0(e.he100_horas)),
    he100_valor: r2(numOr0(ing.he100_valor)),

    // Alimentación (no aportable)
    alimentacion_dias: r2(numOr0(alimDiasUsados)),
    alimentacion_tarifa: r2(numOr0(alimTarifaUsada)),
    alimentacion_valor: r2(numOr0(ing.alimentacion_valor)),
    compensacion: r2(numOr0(ing.compensacion)),

    // Totales de ingresos
    total_no_aportables: r2(numOr0(ing.total_no_aportables)),
    total_ingresos_iess: r2(numOr0(ing.total_ingresos_iess)),
    ingresos_pagables: r2(numOr0(ing.ingresos_pagables)),

    // Décimos (mensualizados)
    decimo_13: r2(numOr0(dec.decimo_13)),
    decimo_14: r2(numOr0(dec.decimo_14)),

    // Fondo de Reserva
    fr_derecho: !!fr.derecho,
    fr_modo: fr.modo || 'sin_derecho',
    fr_calculado: r2(numOr0(fr.calculado)),
    fr_pagado: r2(numOr0(fr.pagado)),
    fr_acumulado: r2(numOr0(fr.acumulado)),

    // Descuentos
    anticipos: r2(numOr0(desc.anticipos)),
    prestamos_empresa: r2(numOr0(desc.prestamos_empresa)),
    crediflash: r2(numOr0(desc.crediflash)),
    saludsa: r2(numOr0(desc.saludsa)),
    seguro_accidentes: r2(numOr0(desc.seguro_accidentes)),
    iess_quiro_monto: r2(numOr0(desc.iess_quiro_monto)),
    deduccion_dias: r2(numOr0(desc.deduccion_dias)), // faltas + atrasos monetizados
    ap_pers_iess: r2(numOr0(desc.ap_pers_iess)),
    total_descuentos: r2(numOr0(desc.total_descuentos)),

    // Totales finales
    valor_final_recibir: r2(numOr0(e.valor_final_recibir)),
    costo_empleador: r2(numOr0(e.costo_empleador)),
  };

  // 6) Forzamos el orden de columnas (útil para el Spreadsheet File)
  const ordenada = {};
  COLS.forEach((k) => { ordenada[k] = (k in fila) ? fila[k] : ''; });
  return ordenada;
});

// 7) Salida: una fila por item.json (para que el Spreadsheet File las escriba en un solo XLSX)
return filas.map((row) => ({ json: row }));

