// === Function — Unir Excel+DB (robusto, con limpieza de alias correcta) ===
// Run once for all items: ON

const APPLY_FILTER = true; // pon false si quieres ver TODO sin filtrar

const onlyDigits = s => (s ?? '').toString().replace(/\D/g,'');
const toNum = v => {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  let s = String(v).trim().replace(/[^\d.,-]/g,'');
  const lc = s.lastIndexOf(','), ld = s.lastIndexOf('.');
  if (lc > ld) s = s.slice(0, lc).replace(/[^\d-]/g,'') + '.' + s.slice(lc+1).replace(/\D/g,'');
  else if (ld > lc) s = s.slice(0, ld).replace(/[^\d-]/g,'') + '.' + s.slice(ld+1).replace(/\D/g,'');
  else s = s.replace(/[^\d-]/g,'');
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
};

// Detectores de procedencia
const looksDB = (o) => {
  if (!o) return false;
  if ('en_db' in o) return !!o.en_db;
  return Object.keys(o).some(k => k.startsWith('db_')) || ('db_estado' in o);
};

const looksArchivo = (o) => {
  if (!o) return false;
  if ('en_archivo' in o) return !!o.en_archivo;
  const keys = Object.keys(o).map(k => k.toLowerCase());
  const set = new Set(keys);
  const possibles = [
    'alimentacion_dias','dias_alimentacion','alimentacion','alimentación',
    'alimentaciondias','diasalimentacion','alimentación_días',
    'alimentaciòn','alimen', // variante con ò
    'he_50_cantidad','he_100_cantidad','he50','he100','50','100',
    'atrasos_dias','faltas_injustificadas','permiso','reposo',
    'sueldo_variable','transporte','movilizacion','otros_ingresos'
  ];
  return possibles.some(k => set.has(k));
};

// --- Alimentación: CANON + ALIASES (¡no borres el CANON!)
const ALIM_DIAS_CANON = 'alimentacion_dias';
const ALIM_DIAS_ALIASES = [
  'dias_alimentacion','alimentacion','alimentación',
  'alimentaciondias','diasalimentacion','alimentación_días',
  'Alimentación','Alimentaciòn','alimentaciòn'
];

// Busca días de alimentación en CANON primero, luego en ALIASES
const pickAlimDias = (obj) => {
  if (Object.prototype.hasOwnProperty.call(obj, ALIM_DIAS_CANON)) {
    const n = toNum(obj[ALIM_DIAS_CANON]);
    if (Number.isFinite(n)) return n;
  }
  for (const k of ALIM_DIAS_ALIASES) {
    if (Object.prototype.hasOwnProperty.call(obj, k)) {
      const n = toNum(obj[k]);
      if (Number.isFinite(n)) return n;
    }
  }
  return null;
};

// Derivar identificación aunque la columna cambie (Cédula/CI/DNI/etc)
const getId = (row) => {
  const direct = row.identificacion ?? row.cedula ?? row.CI ?? row.DNI ?? row.Id ?? row.ID ?? row['Cédula'];
  if (direct) {
    const d = onlyDigits(direct);
    if (d) return d;
  }
  for (const [k,v] of Object.entries(row)) {
    const nk = k.normalize('NFD').replace(/\p{Diacritic}/gu,'').toLowerCase();
    if (/(ident|cedul|dni|ced|ci)\b/.test(nk)) {
      const d = onlyDigits(v);
      if (d) return d;
    }
  }
  return '';
};

const map = new Map();

for (const { json } of items) {
  const id = getId(json);
  if (!id) continue;

  const prev = map.get(id) || { identificacion: id, en_archivo: false, en_db: false };
  const merged = { ...prev, ...json }; // merge superficial

  // Procedencia (inferida si no viene)
  const inferDB = looksDB(json);
  const inferArchivo = looksArchivo(json);
  merged.en_db = prev.en_db || !!json.en_db || inferDB;
  merged.en_archivo = prev.en_archivo || !!json.en_archivo || inferArchivo;

  // Conserva estado de DB si viene
  if (json.db_estado !== undefined) merged.db_estado = json.db_estado;

  // --- Alimentación: prioriza archivo; no pisar un >0 previo con 0
  const diasNew  = pickAlimDias(json);
  const diasPrev = (ALIM_DIAS_CANON in prev) ? toNum(prev[ALIM_DIAS_CANON]) : null;

  if (diasNew !== null) {
    if (inferArchivo || json.en_archivo) {
      merged[ALIM_DIAS_CANON] = (diasPrev !== null && diasPrev > 0 && diasNew === 0) ? diasPrev : diasNew;
      merged._alimdias_source = 'archivo';
    } else {
      // viene de DB u otros; si no había previo, lo tomamos
      if (!(diasPrev !== null)) {
        merged[ALIM_DIAS_CANON] = diasNew;
        merged._alimdias_source = merged._alimdias_source || 'otro';
      }
    }
  } else if (diasPrev !== null) {
    merged[ALIM_DIAS_CANON] = diasPrev;
  }

  // 🔧 Canonicaliza: elimina SOLO alias crudos (NUNCA el CANON)
  for (const k of ALIM_DIAS_ALIASES) {
    if (k in merged) delete merged[k];
  }

  map.set(id, merged);
}

// Filtro final
let out = Array.from(map.values());
if (APPLY_FILTER) {
  let filtered = out.filter(r => {
    if (r.en_archivo) return true;
    const estado = String(r.db_estado ?? 'activo').toLowerCase();
    if (r.en_db && estado === 'activo') return true;
    return false;
  });
  if (filtered.length) out = filtered;
  else console.warn('⚠️ Unir Excel+DB: filtro dejó 0 items; devolviendo SIN FILTRAR.');
}

// Log rápido
const stats = {
  input_items: items.length,
  ids_conocidos: map.size,
  salida: out.length,
  with_any_alim_dias: out.filter(x => Object.prototype.hasOwnProperty.call(x, ALIM_DIAS_CANON)).length,
  with_alim_dias_gt0: out.filter(x => toNum(x[ALIM_DIAS_CANON]) > 0).length,
  flag_db_true: out.filter(x => x.db_valor_alimentacion_4_5 === true).length,
  flag_db_false: out.filter(x => x.db_valor_alimentacion_4_5 === false).length
};
console.log('== Unir Excel+DB (stats) ==', stats);

// Fallback extremo
if (!out.length) {
  console.warn('⚠️ Unir Excel+DB: sin items de salida; devolviendo items originales como fallback.');
  return items;
}

return out.map(json => ({ json }));

// Recorremos los items que llegan del Webhook
for (const item of items) {
  if (!item.binary) continue;

  // Recorremos todas las propiedades binarias: file0, file1, file2, file3, file4...
  for (const key of Object.keys(item.binary)) {
    const bin = item.binary[key];

    // Si este binario es el archivo ajustes.xlsx, corregimos su metadata
    if (bin.fileName === 'ajustes.xlsx') {
      bin.fileExtension = 'xlsx';
      bin.mimeType = 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
    }
  }
}

return items;

// Node: Ajustes nómina limpios

const onlyDigits = s => (s ?? '').toString().replace(/\D/g,'');

for (const item of items) {
  const j = item.json;

  // 1) Normalizar empresa (mayúsculas, sin espacios)
  j.empresa = (j.empresa ?? '').toString().trim().toUpperCase();

  // 2) Cédula: solo dígitos
  j.identificacion = onlyDigits(j.identificacion);

  // 3) Nombre: quitar espacios sobrantes
  if (j.nombre != null) {
    j.nombre = j.nombre.toString().trim();
  }

  // 4) Asegurar tipos numéricos en los *_fix
  if (j.dias_trabajados_fix != null && j.dias_trabajados_fix !== '') {
    j.dias_trabajados_fix = Number(j.dias_trabajados_fix);
  }

  if (j.utilidades_fix != null && j.utilidades_fix !== '') {
    j.utilidades_fix = Number(j.utilidades_fix);
  }

  if (j.dias_alimentacion_fix != null && j.dias_alimentacion_fix !== '') {
    j.dias_alimentacion_fix = Number(j.dias_alimentacion_fix);
  }

  // 5) Fondo de reserva (si luego lo añades al Excel)
  if (j.fondo_reserva_fix != null && j.fondo_reserva_fix !== '') {
    j.fondo_reserva_fix = j.fondo_reserva_fix.toString().trim().toUpperCase();
  } else {
    j.fondo_reserva_fix = null;
  }

  // 6) Clave auxiliar para debug/joins
  j.clave = `${j.empresa}-${j.identificacion}`;

  item.json = j;
}

return items;

// === Function — Union Base FR (empleados + idx + quiro + ajustes FR) ===
// Entrada: items variados desde Merge
// Salida: 1 solo item con { ...meta, empleados: [...] }

const items = $input.all().map(i => i.json);

// Helper para convertir a número de forma segura
const toNum = (v) => {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  const n = Number(String(v).replace(/[^\d.-]/g, ''));
  return Number.isFinite(n) ? n : 0;
};

// Helper: "tiene valor" (no null/undefined/'')
const hasVal = (v) => v !== null && v !== undefined && v !== '';

// Helper: normalizar identificación (solo dígitos)
const normId = (v) => String(v ?? '').replace(/\D/g, '');

// Helper: asignar si hay valor (no pisa con null/undefined/'')
const setIfVal = (obj, key, val) => {
  if (hasVal(val)) obj[key] = val;
};

// Helper: asignar si el campo destino está vacío
const setIfEmpty = (obj, key, val) => {
  if (!hasVal(obj[key]) && hasVal(val)) obj[key] = val;
};

// Helper especial: aplicar un *_fix SOLO si es numérico y > 0
const setFixIfPositive = (obj, key, val) => {
  const n = toNum(val);
  if (n > 0) obj[key] = n;
};

// Detectar si un item “parece” ajuste FR
const isAjusteFR = (o) => {
  if (!o) return false;
  const keys = Object.keys(o);
  const hasFix = keys.some(k => k.endsWith('_fix'));
  const hasEmpresa = hasVal(o.empresa) || hasVal(o.codigo_empresa) || hasVal(o.empresa_code);
  return hasFix || (hasEmpresa && (hasVal(o.identificacion) || hasVal(o.cedula)));
};

// --- NORMALIZADOR DE MAPA QUIRO ---
// Acepta quiro como:
// 1) mapa: { "172...": {monto_quiro: ...} }
// 2) mapa por clave: { "QR-172...": {...} }
// 3) arreglo: [ {identificacion/cedula/clave, monto_quiro/...}, ... ]
// Devuelve mapa por CÉDULA (solo dígitos): { "172...": {monto_quiro, nuts, origen} }
const normalizeQuiroMap = (quiroRaw) => {
  const out = {};

  const upsert = (keyLike, valObj) => {
    const id = normId(keyLike);
    if (!id) return;

    const v = valObj ?? {};
    // monto_quiro puede venir con distintos nombres o incluso como número directo
    const monto =
      (typeof v === 'number' ? v : undefined) ??
      v.monto_quiro ??
      v.monto ??
      v.valor ??
      v.descuento ??
      v.total ??
      v.aporte ??
      0;

    out[id] = {
      ...v,
      monto_quiro: toNum(monto),
      nuts: v.nuts ?? v.NUTS ?? v.nut ?? v.NUT ?? v.quiro_nuts ?? '',
      origen: v.origen ?? v.ORIGEN ?? v.source ?? v.fuente ?? '',
    };
  };

  if (!quiroRaw) return out;

  if (Array.isArray(quiroRaw)) {
    for (const row of quiroRaw) {
      if (!row) continue;
      upsert(row.identificacion ?? row.cedula ?? row.clave, row);
    }
    return out;
  }

  if (typeof quiroRaw === 'object') {
    for (const [k, v] of Object.entries(quiroRaw)) {
      // si el valor es un objeto con identificacion, usa eso; si no, usa la key
      const keyLike = (v && typeof v === 'object' && (v.identificacion || v.cedula || v.clave))
        ? (v.identificacion ?? v.cedula ?? v.clave)
        : k;
      upsert(keyLike, v);
    }
    return out;
  }

  return out;
};

// Contenedores
let meta = {};                 // datos generales de la nómina
let quiroPorId = {};           // mapa por cédula (normalizado)
let idx = {};                  // mapa por identificación desde PDF FR (idx)
const basePorId = {};          // empleados venidos de Base FR / archivo
const ajustesPorId = {};       // filas del Excel de ajustes FR

// Clasificamos todos los items de entrada
for (const obj of items) {
  if (!obj || typeof obj !== 'object') continue;

  // 1) Meta general
  if (hasVal(obj.fecha_nomina) && hasVal(obj.periodo_key)) {
    meta = obj;
    continue;
  }

  // 2) Quirografarios (normalizamos a mapa por cédula)
  if (obj.quiro) {
    quiroPorId = normalizeQuiroMap(obj.quiro);
    continue;
  }

  // 3) Mapa idx (PDF FR)
  if (obj.idx && typeof obj.idx === 'object') {
    idx = obj.idx || {};
    continue;
  }

  // 4) Empleados de la base / archivo
  if (
    Object.prototype.hasOwnProperty.call(obj, 'en_db') ||
    Object.prototype.hasOwnProperty.call(obj, 'en_archivo')
  ) {
    const id = normId(obj.identificacion ?? obj.cedula);
    if (!id) continue;
    basePorId[id] = obj;
    continue;
  }

  // 5) Ajustes manuales FR (Excel)
  if (isAjusteFR(obj) && (hasVal(obj.identificacion) || hasVal(obj.cedula))) {
    const id = normId(obj.identificacion ?? obj.cedula);
    if (!id) continue;
    ajustesPorId[id] = obj;
    continue;
  }
}

// Armamos el set de todas las cédulas que aparecen en cualquier fuente
const allIds = new Set([
  ...Object.keys(basePorId),
  ...Object.keys(quiroPorId || {}),
  ...Object.keys(idx || {}),
  ...Object.keys(ajustesPorId || {}),
]);

const empleados = [];

// helper: buscar quiro por id con variantes de clave (por si en algún punto quedó con prefijos)
const getQuiro = (id, empresa) => {
  const emp = empresa ?? meta.empresa ?? null;
  return (
    quiroPorId[id] ||
    (emp ? quiroPorId[`${emp}-${id}`] : undefined) ||
    (emp ? quiroPorId[`${emp}_${id}`] : undefined) ||
    quiroPorId[`QR-${id}`] ||
    quiroPorId[`QR_${id}`] ||
    {}
  );
};

for (const rawId of allIds) {
  const id   = normId(rawId);
  const base = basePorId[id] || {};
  const a    = ajustesPorId[id] || {};
  const i    = idx[id] || {};

  // empezamos con base (para no perder campos previos)
  const emp = {
    ...(base || {}),
    identificacion: id,
  };

  // Empresa/nombre lo antes posible (para ayudar a buscar quiro con prefijos)
  setIfEmpty(emp, 'empresa', base.empresa ?? base.db_codigo_empresa ?? meta.empresa ?? null);
  setIfEmpty(emp, 'nombre',  base.nombre  ?? base.db_nombre ?? null);

  // --------------------------------
  // 0) NORMALIZACIÓN de campos de ingresos/egresos (para no “perder” sueldo_variable, etc.)
  // --------------------------------
  setIfEmpty(emp, 'sueldo_variable',  base.sueldo_variable  ?? base.db_sueldo_variable  ?? 0);
  setIfEmpty(emp, 'transporte',       base.transporte       ?? base.db_transporte       ?? 0);
  setIfEmpty(emp, 'movilizacion',     base.movilizacion     ?? base.db_movilizacion     ?? 0);
  setIfEmpty(emp, 'compensacion',     base.compensacion     ?? base.db_compensacion     ?? 0);
  setIfEmpty(emp, 'utilidades',       base.utilidades       ?? base.db_utilidades       ?? 0);
  setIfEmpty(emp, 'otros_ingresos',   base.otros_ingresos   ?? base.db_otros_ingresos   ?? 0);

  setIfEmpty(emp, 'anticipos',         base.anticipos         ?? base.db_anticipos         ?? 0);
  setIfEmpty(emp, 'prestamos_empresa', base.prestamos_empresa ?? base.db_prestamos_empresa ?? 0);
  setIfEmpty(emp, 'crediflash',        base.crediflash        ?? base.db_crediflash        ?? 0);
  setIfEmpty(emp, 'iess_quirograficos',base.iess_quirograficos?? base.db_iess_quirograficos?? 0);

  emp.sueldo_variable     = toNum(emp.sueldo_variable);
  emp.transporte          = toNum(emp.transporte);
  emp.movilizacion        = toNum(emp.movilizacion);
  emp.compensacion        = toNum(emp.compensacion);
  emp.utilidades          = toNum(emp.utilidades);
  emp.otros_ingresos      = toNum(emp.otros_ingresos);
  emp.anticipos           = toNum(emp.anticipos);
  emp.prestamos_empresa   = toNum(emp.prestamos_empresa);
  emp.crediflash          = toNum(emp.crediflash);
  emp.iess_quirograficos  = toNum(emp.iess_quirograficos);

  // --------------------------------
  // 1) Datos desde idx (PDF Fondo R)
  // --------------------------------
  emp.fr_derecho      = (i.fr_derecho      ?? emp.fr_derecho      ?? false);
  emp.fr_acumulacion  = (i.fr_acumulacion  ?? emp.fr_acumulacion  ?? false);
  emp.fr_tiene_cargos = (i.fr_tiene_cargos ?? emp.fr_tiene_cargos ?? false);

  emp.fr_fecha_solicitud = (i.fr_fecha_solicitud ?? emp.fr_fecha_solicitud ?? null);
  emp.sucursal           = (i.sucursal           ?? emp.sucursal           ?? null);
  emp.aportes_periodo    = (i.aportes_periodo    ?? emp.aportes_periodo    ?? null);

  emp.fr_tiene_solicitud =
    (i.fr_tiene_solicitud ??
      (hasVal(i.fr_fecha_solicitud) ? true : (emp.fr_tiene_solicitud ?? false)));

  // --------------------------------
  // 2) Descuentos Base FR
  // --------------------------------
  if (
    Object.prototype.hasOwnProperty.call(base, 'descuento_multa') ||
    Object.prototype.hasOwnProperty.call(base, 'descuento_crediflash')
  ) {
    emp.desc_multa             = base.descuento_multa ?? 0;
    emp.desc_crediflash        = base.descuento_crediflash ?? 0;
    emp.desc_saludsa           = base.descuento_saludsa ?? 0;
    emp.desc_seguro_accidentes = base.descuento_seguro_accidentes ?? 0;
    emp.desc_anticipos         = base.descuento_anticipos ?? 0;
    emp.desc_prestamos         = base.descuento_prestamos ?? 0;
  } else if (base.descuentos && typeof base.descuentos === 'object') {
    const d = base.descuentos;
    emp.desc_multa             = d['_tipo = multa'] ?? 0;
    emp.desc_crediflash        = d['_tipo = crediflash'] ?? 0;
    emp.desc_saludsa           = d['_tipo = saludsa'] ?? 0;
    emp.desc_seguro_accidentes = d['_tipo = seguro_accidentes'] ?? 0;
    emp.desc_anticipos         = d['_tipo = anticipos'] ?? 0;
    emp.desc_prestamos         = d['_tipo = prestamos'] ?? 0;
  } else {
    emp.desc_multa             = 0;
    emp.desc_crediflash        = 0;
    emp.desc_saludsa           = 0;
    emp.desc_seguro_accidentes = 0;
    emp.desc_anticipos         = 0;
    emp.desc_prestamos         = 0;
  }

  emp.desc_multa             = toNum(emp.desc_multa);
  emp.desc_crediflash        = toNum(emp.desc_crediflash);
  emp.desc_saludsa           = toNum(emp.desc_saludsa);
  emp.desc_seguro_accidentes = toNum(emp.desc_seguro_accidentes);
  emp.desc_anticipos         = toNum(emp.desc_anticipos);
  emp.desc_prestamos         = toNum(emp.desc_prestamos);

  // --------------------------------
  // 3) Quirografarios ✅ FIX: NO pisar lo que ya viene en base, y solo sobreescribir si el mapa trae monto > 0
  // --------------------------------

  // 3.1) Conserva lo que ya viene en el registro
  emp.monto_quiro = toNum(base.monto_quiro ?? emp.monto_quiro ?? 0);

  // nuts/origen pueden venir como "nuts"/"origen" o como "quiro_nuts"/"quiro_origen"
  emp.quiro_nuts   = base.quiro_nuts   ?? base.nuts   ?? emp.quiro_nuts   ?? '';
  emp.quiro_origen = base.quiro_origen ?? base.origen ?? emp.quiro_origen ?? '';

  // 3.2) Si existe un mapa de quiros (cuando venga como item aparte), úsalo SOLO si trae monto útil
  const q = getQuiro(id, emp.empresa);
  const qMonto =
    (typeof q === 'number' ? q : undefined) ??
    q.monto_quiro ??
    q.monto ??
    q.valor ??
    q.descuento ??
    q.total ??
    null;

  // Solo sobreescribir si qMonto viene y es > 0
  if (qMonto !== null && toNum(qMonto) > 0) {
    emp.monto_quiro  = toNum(qMonto);
    emp.quiro_nuts   = q.nuts ?? q.NUTS ?? q.nut ?? q.NUT ?? q.quiro_nuts ?? emp.quiro_nuts ?? '';
    emp.quiro_origen = q.origen ?? q.ORIGEN ?? q.source ?? q.fuente ?? emp.quiro_origen ?? '';
  }

  // --------------------------------
  // 4) Ajustes manuales (NO PISAR con null) + regla de negocio para días
  // --------------------------------
  if (hasVal(a.empresa)) emp.empresa = a.empresa;
  else emp.empresa = emp.empresa ?? base.db_codigo_empresa ?? meta.empresa ?? null;

  if (hasVal(a.nombre)) emp.nombre = a.nombre;
  else emp.nombre = emp.nombre ?? base.db_nombre ?? null;

  // OJO: solo aplicamos _fix si es > 0 (y en especial para días)
  // Si para otros rubros quieres permitir 0 como override intencional, cámbialo caso por caso.
  setFixIfPositive(emp, 'utilidades_fix',        a.utilidades_fix);
  setFixIfPositive(emp, 'dias_alimentacion_fix', a.dias_alimentacion_fix);
  setFixIfPositive(emp, 'dias_trabajados_fix',   a.dias_trabajados_fix);
  setFixIfPositive(emp, 'fondo_reserva_fix',     a.fondo_reserva_fix);

  // Asegurar que existan las llaves *_fix (null si no aplica)
  if (!Object.prototype.hasOwnProperty.call(emp, 'utilidades_fix'))         emp.utilidades_fix = null;
  if (!Object.prototype.hasOwnProperty.call(emp, 'dias_alimentacion_fix'))  emp.dias_alimentacion_fix = null;
  if (!Object.prototype.hasOwnProperty.call(emp, 'dias_trabajados_fix'))    emp.dias_trabajados_fix = null;
  if (!Object.prototype.hasOwnProperty.call(emp, 'fondo_reserva_fix'))      emp.fondo_reserva_fix = null;

  if (hasVal(a.clave)) emp.clave = a.clave;
  else if (emp.empresa && id) emp.clave = `${emp.empresa}-${id}`;
  else emp.clave = null;

  // --------------------------------
  // 5) Sueldo base y valor_alimentacion_4_5
  // --------------------------------
  const salBase = toNum(base.salario_base) || toNum(base.db_salario_base) || toNum(emp.salario_base);
  emp.salario_base = salBase;

  emp.valor_alimentacion_4_5 =
    (base.db_valor_alimentacion_4_5 ?? emp.valor_alimentacion_4_5 ?? false);

  // --------------------------------
  // 6) DÍAS TRABAJADOS (regla negocio): PRIMERO AJUSTE (>0), SI NO 30 SIEMPRE
  // --------------------------------
  const dtFix = toNum(emp.dias_trabajados_fix);
  emp.dias_trabajados = (dtFix > 0) ? dtFix : 30;

  empleados.push(emp);
}

// Si meta no tenía empresa, intentamos tomarla del primer empleado
if (!meta.empresa && empleados.length > 0) {
  meta.empresa = empleados[0].empresa ?? null;
}

// Salida lista para el siguiente nodo (Armar lote)
return [
  {
    json: {
      ...meta,
      empleados,
    },
  },
];

function toNum(v) {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;

  let s = String(v).trim().replace(/[^\d.,-]/g, '');
  if (!s) return 0;

  const comma = s.lastIndexOf(',');
  const dot = s.lastIndexOf('.');

  if (comma > dot) {
    s = s.slice(0, comma).replace(/[^\d-]/g, '') + '.' + s.slice(comma + 1).replace(/\D/g, '');
  } else if (dot > comma) {
    s = s.slice(0, dot).replace(/[^\d-]/g, '') + '.' + s.slice(dot + 1).replace(/\D/g, '');
  }

  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

// 1) Empleados: usar lo que entra al nodo (salida del Merge)
const empleadosItems = items;

// 2) Índice de descuentos
let descuentosIdx = {};
const descuentosItems = $items('Index descuentos');

if (descuentosItems?.length) {
  const dJson = descuentosItems[0].json || {};
  if (dJson.descuentos && typeof dJson.descuentos === 'object') {
    descuentosIdx = dJson.descuentos;
  }
}

const out = [];

for (const empItem of empleadosItems) {
  const emp = { ...(empItem.json || {}) };

  // Normalización robusta
  const id = String(emp.identificacion ?? '').replace(/\D/g, '').padStart(10, '0');

  const desc = (id && descuentosIdx[id]) ? descuentosIdx[id] : {};
  const merged = { ...emp };

  merged.descuentos = desc;

  merged.descuento_multa             = toNum(desc['_tipo = multa']);
  merged.descuento_crediflash        = toNum(desc['_tipo = crediflash']);
  merged.descuento_saludsa           = toNum(desc['_tipo = saludsa']);
  merged.descuento_seguro_accidentes = toNum(desc['_tipo = seguro_accidentes']);
  merged.descuento_anticipos         = toNum(desc['_tipo = anticipos']);
  merged.descuento_prestamos         = toNum(desc['_tipo = prestamos']);

  if (merged.en_db && merged.db_salario_base != null && merged.db_salario_base !== '') {
    merged.salario_base = toNum(merged.db_salario_base);
  } else if (merged.salario_base != null && merged.salario_base !== '') {
    merged.salario_base = toNum(merged.salario_base);
  } else {
    merged.salario_base = 0;
  }

  out.push({ json: merged });
}

return out;

function normalizeId(v) {
  if (v === null || v === undefined) return null;
  const digits = String(v).trim().replace(/\D/g, '');
  if (!digits) return null;
  if (digits.length === 9) return digits.padStart(10, '0');
  return digits;
}

