const binary = {};

const tryBinary = (nodeName, prop) => {
  try {
    const nodeItems = $(nodeName).all();
    for (const item of nodeItems) {
      if (item.binary && item.binary[prop]) {
        binary[prop] = item.binary[prop];
        return;
      }
    }
  } catch (e) {
    // Nodo no ejecutado o sin datos — OK
  }
};

